// Home Assistant 设备控制脚本
const webhookData = $input.first().json;

// 提取参数
const action = webhookData.action || 'get_status';
const entityId = webhookData.entity_id;
const command = webhookData.command || 'toggle';
const haUrl = webhookData.ha_url || 'http://localhost:8123';
const haToken = webhookData.ha_token || 'REDACTED_HA_TOKEN_4';

if (!entityId) {
  return [{
    json: {
      success: false,
      error: 'entity_id is required',
      timestamp: new Date().toISOString()
    }
  }];
}

// 准备HTTP请求参数
let requestUrl, requestMethod, requestData;

if (action === 'get_status') {
  // 获取设备状态
  requestUrl = `${haUrl}/api/states/${entityId}`;
  requestMethod = 'GET';
  requestData = null;
} else if (action === 'control') {
  // 控制设备
  const domain = entityId.split('.')[0];
  let service;

  if (command === 'on') {
    service = 'turn_on';
  } else if (command === 'off') {
    service = 'turn_off';
  } else if (command === 'toggle') {
    service = 'toggle';
  } else {
    service = command; // 允许自定义服务
  }

  requestUrl = `${haUrl}/api/services/${domain}/${service}`;
  requestMethod = 'POST';
  requestData = {
    entity_id: entityId
  };
} else {
  return [{
    json: {
      success: false,
      error: 'Invalid action. Use "get_status" or "control"',
      timestamp: new Date().toISOString()
    }
  }];
}

// 返回请求参数
return [{
  json: {
    requestUrl,
    requestMethod,
    requestData,
    haToken,
    originalAction: action,
    entityId,
    command
  }
}];

// 处理Home Assistant API响应
const requestData = $input.first().json;
const haResponse = requestData.body ? JSON.parse(requestData.body) : requestData;

const originalAction = $('Prepare Request').first().json.originalAction;
const entityId = $('Prepare Request').first().json.entityId;
const command = $('Prepare Request').first().json.command;

let response;

if (originalAction === 'get_status') {
  // 状态查询响应
  if (haResponse.entity_id) {
    response = {
      success: true,
      action: 'get_status',
      entity_id: haResponse.entity_id,
      current_state: haResponse.state,
      friendly_name: haResponse.attributes?.friendly_name || entityId,
      last_changed: haResponse.last_changed,
      attributes: haResponse.attributes,
      timestamp: new Date().toISOString()
    };
  } else {
    response = {
      success: false,
      error: 'Device not found or API error',
      entity_id: entityId,
      timestamp: new Date().toISOString()
    };
  }
} else if (originalAction === 'control') {
  // 控制命令响应
  if (Array.isArray(haResponse) && haResponse.length > 0) {
    const deviceState = haResponse[0];
    response = {
      success: true,
      action: 'control',
      command: command,
      entity_id: deviceState.entity_id,
      current_state: deviceState.state,
      friendly_name: deviceState.attributes?.friendly_name || entityId,
      message: `Device ${command} command executed successfully`,
      timestamp: new Date().toISOString()
    };
  } else {
    response = {
      success: true,
      action: 'control',
      command: command,
      entity_id: entityId,
      message: `Command ${command} sent to ${entityId}`,
      timestamp: new Date().toISOString()
    };
  }
} else {
  response = {
    success: false,
    error: 'Unknown action type',
    timestamp: new Date().toISOString()
  };
}

return [{ json: response }];
